import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import { BarChart } from '@mui/x-charts';
import response from './response.json';

interface RecentContact {
  name: string;
  lastMessageSnippet: string;
  timestamp: string;
}

interface MessageVolume {
  hour: string;
  messages: number;
}

interface MessagingData {
  unreadConversations: number;
  recentContacts: RecentContact[];
  messageVolume: MessageVolume[];
}

export default function Widget() {
  const { unreadConversations, recentContacts, messageVolume } = response.data as MessagingData;
  const { primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#333', color: '#fff' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: primaryColor }}>
              Quick Chat
            </Typography>
            <Typography variant="body2" sx={{ color: '#999' }}>
              Unread Conversations: {unreadConversations}
            </Typography>
          </Box>

          <Box>
            <Typography variant="body2" sx={{ mb: 1, color: '#ccc' }}>
              Recent Contacts
            </Typography>
            <Stack spacing={1}>
              {recentContacts.map((contact, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ fontWeight: 500, color: accentColor }}>
                    {contact.name}
                  </Typography>
                  <Typography variant="caption" sx={{ color: '#777' }}>
                    {contact.lastMessageSnippet}
                  </Typography>
                </Box>
              ))}
            </Stack>
            <Divider sx={{ my: 1, bgcolor: '#444' }} />
          </Box>

          <BarChart
            height={120}
            series={[
              {
                data: messageVolume.map((v) => v.messages),
                color: primaryColor,
              },
            ]}
            xAxis={[
              {
                data: messageVolume.map((v) => v.hour),
                scaleType: 'band',
                tickLabelStyle: {
                  fontSize: 11,
                  fill: '#AAA',
                },
              },
            ]}
            margin={{ top: 10, bottom: 30, left: 40, right: 10 }}
            sx={{
              '& .MuiBarElement-root': {
                rx: 4,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
